const body = $input.first().json;

// ── Pull form fields ──────────────────────────────────────────
const employeeName = String(body['Your Full Name'] || body.employeeName || '').trim();
const employeeEmail = String(body['Your Email'] || body.employeeEmail || '').trim().toLowerCase();
const managerEmail = String(body['Manager Email'] || body.managerEmail || '').trim().toLowerCase();
const category = String(body['Expense Category'] || body.category || 'Other').trim();
const fileUrl = String(body['Receipt Photo or PDF URL'] || body.fileUrl || '').trim();
const businessPurpose = String(body['Business Purpose'] || body.businessPurpose || '').trim();
const projectCode = String(body['Project Code'] || body.projectCode || '').trim();

// ── Required field guards ─────────────────────────────────────
if (!employeeName) throw new Error('Employee name is required.');
if (!employeeEmail) throw new Error('Employee email is required.');
if (!managerEmail) throw new Error('Manager email is required.');
if (!businessPurpose) throw new Error('Business purpose is required.');
if (!fileUrl && !body.filename) throw new Error('Provide a receipt file URL or binary upload.');

// ── Email format validation ───────────────────────────────────
const emailRx = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRx.test(employeeEmail)) throw new Error(`Invalid employee email: ${employeeEmail}`);
if (!emailRx.test(managerEmail)) throw new Error(`Invalid manager email: ${managerEmail}`);
if (employeeEmail === managerEmail) throw new Error('Employee and manager email must be different.');

// ── Filename & extension ──────────────────────────────────────
const filename = body.filename ||
  fileUrl.split('?')[0].split('/').pop() ||
  'receipt.jpg';
const ext = filename.split('.').pop()?.toLowerCase() || 'jpg';
const allowedExts = ['jpg', 'jpeg', 'png', 'pdf', 'heic', 'webp'];
if (!allowedExts.includes(ext)) {
  throw new Error(`File type .${ext} not supported. Accepted: ${allowedExts.join(', ')}`);
}

// ── Generate expense ID ───────────────────────────────────────
const expenseId = `EXP-${Date.now()}`;
const employeeSlug = employeeName.toLowerCase().replace(/[^a-z0-9]/g, '-').slice(0, 20);
const structuredFilename = `${expenseId}-${employeeSlug}.${ext}`;

// ── Auto-approve threshold from env var ───────────────────────
const autoApproveThreshold = parseFloat($vars.AUTO_APPROVE_THRESHOLD || '50');

return [{
  json: {
    expenseId,
    employeeName,
    employeeEmail,
    managerEmail,
    category,
    businessPurpose,
    projectCode: projectCode || null,
    fileUrl: fileUrl || null,
    filename,
    structuredFilename,
    ext,
    autoApproveThreshold,
    submittedAt: new Date().toISOString()
  }
}];

const uploadResp = $input.first().json;
const meta = $('Validate & Build Expense Record').first().json;

const cdnUrl =
  uploadResp.url ||
  uploadResp.link ||
  uploadResp.data?.url ||
  uploadResp.file?.url ||
  uploadResp.shortUrl;

if (!cdnUrl) {
  throw new Error('UploadToURL returned no public URL. Raw: ' + JSON.stringify(uploadResp).slice(0, 300));
}

return [{
  json: {
    ...meta,
    cdnUrl: cdnUrl.replace(/^http:\/\//, 'https://'),
    uploadId: uploadResp.id || uploadResp.data?.id || null,
    fileSizeBytes: uploadResp.size || uploadResp.data?.size || null
  }
}];

const mindeeResp = $input.first().json;
const meta = $('Extract CDN URL').first().json;

// ── Navigate Mindee v5 response structure ─────────────────────
const prediction = mindeeResp.document?.inference?.prediction || {};

// ── Helper: extract value + confidence from Mindee field ──────
const getField = (field) => ({
  value: field?.value ?? null,
  confidence: field?.confidence ?? 0
});

// ── Extract core fields ───────────────────────────────────────
const totalField     = getField(prediction.total_amount);
const taxField       = getField(prediction.total_tax);
const merchantField  = getField(prediction.supplier_name);
const dateField      = getField(prediction.date);
const currencyField  = getField(prediction.locale?.currency || { value: 'USD', confidence: 0.5 });
const categoryField  = getField(prediction.category);
const receiptNumField= getField(prediction.receipt_number);

// ── Normalise values ──────────────────────────────────────────
const total    = parseFloat(totalField.value) || null;
const tax      = parseFloat(taxField.value) || null;
const merchant = String(merchantField.value || 'Unknown Merchant').trim();
const date     = dateField.value
  ? new Date(dateField.value).toISOString().split('T')[0]
  : new Date().toISOString().split('T')[0];
const currency = String(currencyField.value || 'USD').toUpperCase().slice(0, 3);
const detectedCategory = categoryField.value || meta.category;
const receiptNumber = receiptNumField.value || null;

// ── Composite confidence score ────────────────────────────────
// Weight by importance: total (40%), merchant (30%), date (20%), tax (10%)
const compositeConfidence = (
  totalField.confidence * 0.40 +
  merchantField.confidence * 0.30 +
  dateField.confidence * 0.20 +
  taxField.confidence * 0.10
);
const confidenceScore = Math.round(compositeConfidence * 100) / 100;

// ── Flag missing required fields ─────────────────────────────
const missingFields = [];
if (total === null) missingFields.push('total');
if (merchantField.confidence < 0.5) missingFields.push('merchant (low confidence)');
if (!dateField.value) missingFields.push('date');

// ── Auto-approve logic ────────────────────────────────────────
// Auto-approve only if: high confidence AND total within threshold AND no missing fields
const meetsAutoApprove =
  confidenceScore >= 0.85 &&
  total !== null &&
  total <= meta.autoApproveThreshold &&
  missingFields.length === 0;

const approvalRoute = meetsAutoApprove ? 'auto' : 'manager';

// ── Format for display ────────────────────────────────────────
const totalFormatted = total !== null
  ? `${currency} ${total.toFixed(2)}`
  : 'Not detected';

return [{
  json: {
    ...meta,
    // Extracted
    merchant,
    total,
    tax,
    currency,
    date,
    detectedCategory,
    receiptNumber,
    // Confidence
    confidenceScore,
    missingFields,
    perFieldConfidence: {
      total: totalField.confidence,
      merchant: merchantField.confidence,
      date: dateField.confidence,
      tax: taxField.confidence
    },
    // Routing
    approvalRoute,
    meetsAutoApprove,
    // Display
    totalFormatted,
    ocrStatus: missingFields.length === 0 ? 'complete' : 'partial'
  }
}];

// Auto-approve path — mark as approved immediately
const data = $input.first().json;
const reimbursementDays = data.total <= 25 ? 3 : 5;

return [{
  json: {
    ...data,
    approvalStatus: 'approved',
    approvedBy: 'Auto-approval system',
    approvedAt: new Date().toISOString(),
    rejectionReason: null,
    reimbursementEta: `${reimbursementDays} business days`,
    statusEmoji: '✅'
  }
}];

