// Manager path — pending until Slack response received
// In production: a separate Slack webhook workflow handles the button click
// and updates the expense status via the Expensify/Sheets nodes
const data = $input.first().json;
const slackResp = $input.first().json;

return [{
  json: {
    ...data,
    approvalStatus: 'pending_manager',
    approvedBy: null,
    approvedAt: null,
    rejectionReason: null,
    reimbursementEta: 'Awaiting manager approval',
    statusEmoji: '⏳',
    slackMessageTs: slackResp.ts || null
  }
}];

const expensifyResp = $input.first().json;
// Get data from whichever approval branch ran
const expData =
  $('Mark Auto-Approved').first()?.json ||
  $('Mark Pending Manager Review').first()?.json;

const expensifyId =
  expensifyResp.reportID ||
  expensifyResp.transactionID ||
  expensifyResp.responseMessage ||
  null;

return [{
  json: {
    ...expData,
    expensifyId: String(expensifyId || ''),
    resolvedAt: new Date().toISOString()
  }
}];

